const { chromium } = require("playwright");

(async () => {
  const browser = await chromium.launch({
    proxy: {
      server: "http://host:port",
      username: "user",
      password: "pass",
    },
  });
  const page = await browser.newPage();
  await page.goto("https://httpbin.org/ip");
  console.log(await page.content());
  await browser.close();
})();

const puppeteer = require("puppeteer");

(async () => {
  const browser = await puppeteer.launch({
    args: ["--proxy-server=http://host:port"],
  });
  const page = await browser.newPage();
  await page.authenticate({ username: "user", password: "pass" });
  await page.goto("https://httpbin.org/ip");
  console.log(await page.content());
  await browser.close();
})();

const axios = require("axios");
const { HttpsProxyAgent } = require("https-proxy-agent");

const agent = new HttpsProxyAgent("http://user:pass@host:port");

axios.get("https://httpbin.org/ip", {
  httpAgent: agent,
  httpsProxyAgent: agent,
}).then((r) => console.log(r.data));

package main

import (
    "fmt"
    "io"
    "net/http"
    "net/url"
)

func main() {
    proxyURL, _ := url.Parse("http://user:pass@host:port")
    client := &http.Client{
        Transport: &http.Transport{Proxy: http.ProxyURL(proxyURL)},
    }
    resp, _ := client.Get("https://httpbin.org/ip")
    defer resp.Body.Close()
    body, _ := io.ReadAll(resp.Body)
    fmt.Println(string(body))
}

import java.net.*;
import java.net.http.*;

Authenticator.setDefault(new Authenticator() {
    protected PasswordAuthentication getPasswordAuthentication() {
        return new PasswordAuthentication("user", "pass".toCharArray());
    }
});

HttpClient client = HttpClient.newBuilder()
    .proxy(ProxySelector.of(new InetSocketAddress("host", port)))
    .build();

HttpRequest req = HttpRequest.newBuilder(URI.create("https://httpbin.org/ip")).build();
System.out.println(client.send(req, HttpResponse.BodyHandlers.ofString()).body());

using System.Net;
using System.Net.Http;

var proxy = new WebProxy("http://host:port")
{
    Credentials = new NetworkCredential("user", "pass"),
};

var handler = new HttpClientHandler { Proxy = proxy, UseProxy = true };
using var client = new HttpClient(handler);

var body = await client.GetStringAsync("https://httpbin.org/ip");
